INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DESCRIPTION, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY, UPDATE_BY) VALUES (475, 'cost-pinggu', 'masterGrid', 'CALC', '[{"field":"salemoney","expression":"outPriceRmb / pPerpack * apexPl * (yield / 100)","triggerFields":["outPriceRmb","pPerpack","apexPl","yield"]},{"field":"jgfBatch","expression":"salemoney - totalCost","triggerFields":["salemoney","totalCost"]},{"field":"costPerbox","expression":"totalCost / apexPl * pPerpack","triggerFields":["totalCost","apexPl","pPerpack"]},{"field":"jgfPerqp","expression":"jgfBatch / apexPl * 1000","triggerFields":["jgfBatch","apexPl"]},{"field":"mlPerqp","expression":"jgfPerqp - costPerqp","triggerFields":["jgfPerqp","costPerqp"]},{"field":"yJgRe","expression":"jgfPerqp / 1000 * annualQty","triggerFields":["jgfPerqp","annualQty"]},{"field":"yMl","expression":"mlPerqp / 1000 * annualQty","triggerFields":["mlPerqp","annualQty"]},{"field":"ySale","expression":"salemoney / apexPl * annualQty","triggerFields":["salemoney","apexPl","annualQty"]}]', 0, NULL, 0, SYSDATE, SYSDATE, 'system', NULL);
INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DESCRIPTION, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY, UPDATE_BY) VALUES (476, 'cost-pinggu', 'masterGrid', 'AGGREGATE', '[{"sourceField":"costBatch","targetField":"totalYl","algorithm":"SUM","sourceTab":"material","filter":"dtlUseflag === ''原料''"},{"sourceField":"costBatch","targetField":"totalFl","algorithm":"SUM","sourceTab":"material","filter":"dtlUseflag === ''辅料''"},{"sourceField":"costBatch","targetField":"totalBc","algorithm":"SUM","sourceTab":"package","filter":"dtlUseflag === ''非印字包材'' || dtlUseflag === ''印字包材''"},{"targetField":"totalYl","expression":"totalYl > 0 ? totalYl / 1.13 : totalYl"},{"targetField":"totalFl","expression":"totalYl > 0 ? totalFl / 1.13 : totalFl"},{"targetField":"totalBc","expression":"totalYl > 0 ? totalBc / 1.13 : totalBc"},{"targetField":"totalCost","expression":"totalYl + totalFl + totalBc"}]', 0, NULL, 0, SYSDATE, SYSDATE, 'system', NULL);
